"""
Pulse 런타임 모듈
Pulse 코드 실행 엔진
"""

import asyncio
from typing import Dict, Any
from llm_manager import LLMManager

class PulseRuntime:
    """Pulse 코드 실행 엔진"""

    def __init__(self):
        self.llm_manager = LLMManager()
        self.agents = {}

    async def execute(self, pulse_code: str) -> str:
        """
        Pulse 코드를 실행하고 결과 반환

        Args:
            pulse_code: Pulse 언어로 작성된 코드

        Returns:
            실행 결과 (자연어)
        """

        try:
            # 1. 코드 파싱
            config = self._parse_pulse_code(pulse_code)

            # 2. 에이전트 생성
            agent = self._create_agent(config)

            # 3. 배포
            deployment_result = await self._deploy(agent, config)

            # 4. 결과 반환
            return self._format_result(config, deployment_result)

        except Exception as e:
            return f"❌ 실행 중 오류 발생: {str(e)}"

    def _parse_pulse_code(self, code: str) -> Dict[str, Any]:
        """Pulse 코드 파싱"""
        lines = code.strip().split("\n")
        config = {}

        for line in lines:
            if line.startswith("로서"):
                config["role"] = line.replace("로서", "").strip()
            elif line.startswith("사용"):
                config["resources"] = line.replace("사용", "").strip()
            elif line.startswith("해야할일"):
                config["goal"] = line.replace("해야할일", "").strip()
            elif line.startswith("흐름"):
                config["flow"] = line.replace("흐름", "").strip()
            elif line.startswith("실행"):
                config["deployment"] = line.replace("실행", "").strip()

        return config

    def _create_agent(self, config: Dict[str, Any]):
        """에이전트 객체 생성"""
        from agent import Agent
        return Agent(config)

    async def _deploy(self, agent, config: Dict[str, Any]) -> Dict[str, Any]:
        """에이전트 배포"""

        deployment_type = config.get("deployment", "실시간-감시")

        if "slack" in deployment_type:
            return await agent.deploy_to_slack()
        elif "email" in deployment_type:
            return await agent.deploy_to_email()
        elif "스케줄" in deployment_type:
            return await agent.deploy_scheduled()
        else:
            return {"status": "deployed"}

    def _format_result(self, config: Dict[str, Any], deployment_result: Dict[str, Any]) -> str:
        """결과를 자연어로 포맷팅"""

        role = config.get("role", "에이전트")
        deployment = config.get("deployment", "")

        result = f"✅ {role}이(가) 완료됐어요!\n\n"

        if "slack" in deployment:
            result += f"Slack에서 자동으로 실행됩니다."
        elif "email" in deployment:
            result += f"이메일 자동 발송이 설정되었습니다."
        elif "스케줄" in deployment:
            result += f"정해진 시간에 자동으로 실행됩니다."

        result += f"\n상태: {deployment_result.get('status', 'OK')}"

        return result

