from typing import Dict, Any, List
from datetime import datetime
from dataclasses import dataclass
import logging

logger = logging.getLogger(__name__)


@dataclass
class Metrics:
    """시스템 메트릭"""

    # LLM 메트릭
    llm_total_tokens: int
    llm_total_cost_usd: float
    llm_local_calls: int
    llm_haiku_calls: int
    llm_sonnet_calls: int

    # 에이전트 메트릭
    agents_total: int
    agents_running: int
    agents_stopped: int
    agents_failed: int

    # 캐시 메트릭
    cache_hits: int
    cache_misses: int
    cache_memory_mb: float

    # 요청 메트릭
    requests_total: int
    requests_success: int
    requests_error: int
    average_response_time_ms: float

    timestamp: str


class SystemMonitor:
    """시스템 모니터링"""

    def __init__(self, registry, cache, llm_manager):
        """
        모니터 초기화

        Args:
            registry: AgentRegistry
            cache: PulseCache
            llm_manager: LLMManager
        """
        self.registry = registry
        self.cache = cache
        self.llm_manager = llm_manager
        self.logger = logger

        # 누적 통계
        self.request_count = 0
        self.success_count = 0
        self.error_count = 0
        self.total_response_time_ms = 0
        self.cache_hits = 0
        self.cache_misses = 0

    def record_request(self, success: bool, response_time_ms: float):
        """
        요청 기록

        Args:
            success: 성공 여부
            response_time_ms: 응답 시간 (ms)
        """
        self.request_count += 1
        self.total_response_time_ms += response_time_ms

        if success:
            self.success_count += 1
        else:
            self.error_count += 1

    def record_cache_hit(self):
        """캐시 히트 기록"""
        self.cache_hits += 1

    def record_cache_miss(self):
        """캐시 미스 기록"""
        self.cache_misses += 1

