        # LLM 메트릭
        llm_stats = self.llm_manager.get_usage_stats()

        # 캐시 메트릭
        cache_stats = await self.cache.get_stats()

        # 캐시 히트율
        total_cache = self.cache_hits + self.cache_misses
        cache_hit_ratio = (
            self.cache_hits / total_cache if total_cache > 0 else 0
        )

