#include "uuid.h"
#include <time.h>
#include <stdlib.h>
#include <pthread.h>

// 난수 생성기
static uint32_t random_uint32(void) {
    return (uint32_t)rand();
}

// UUID v4 생성 (Random)
uuid_t uuid_v4_generate(void) {
    uuid_t uuid;
    for (int i = 0; i < 16; i++) {
        uuid.bytes[i] = (uint8_t)(random_uint32() & 0xFF);
    }
    // Version 4
    uuid.bytes[6] = (uuid.bytes[6] & 0x0F) | 0x40;
    // Variant
    uuid.bytes[8] = (uuid.bytes[8] & 0x3F) | 0x80;
    return uuid;
}

// UUID v1 생성 (Time-based)
uuid_t uuid_v1_generate(void) {
    uuid_t uuid;
    time_t now = time(NULL);

    // Timestamp (60-bit)
    uint64_t timestamp = (uint64_t)now;
    uuid.bytes[0] = (timestamp >> 24) & 0xFF;
    uuid.bytes[1] = (timestamp >> 16) & 0xFF;
    uuid.bytes[2] = (timestamp >> 8) & 0xFF;
    uuid.bytes[3] = timestamp & 0xFF;

    // Clock sequence
    uint16_t clock_seq = (uint16_t)random_uint32();
    uuid.bytes[8] = (clock_seq >> 8) & 0xFF;
    uuid.bytes[9] = clock_seq & 0xFF;

    // Node ID (MAC address mock)
    for (int i = 10; i < 16; i++) {
        uuid.bytes[i] = (uint8_t)(random_uint32() & 0xFF);
    }

    // Version 1
    uuid.bytes[6] = (uuid.bytes[6] & 0x0F) | 0x10;
    // Variant
    uuid.bytes[8] = (uuid.bytes[8] & 0x3F) | 0x80;

    return uuid;
}

// UUID를 문자열로 변환
void uuid_to_string(uuid_t uuid, char *str) {
    sprintf(str, "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
        uuid.bytes[0], uuid.bytes[1], uuid.bytes[2], uuid.bytes[3],
        uuid.bytes[4], uuid.bytes[5],
        uuid.bytes[6], uuid.bytes[7],
        uuid.bytes[8], uuid.bytes[9],
        uuid.bytes[10], uuid.bytes[11], uuid.bytes[12], uuid.bytes[13], uuid.bytes[14], uuid.bytes[15]);
}

// 문자열에서 UUID 파싱
uuid_t uuid_from_string(const char *str) {
    uuid_t uuid;
    sscanf(str, "%2hhx%2hhx%2hhx%2hhx-%2hhx%2hhx-%2hhx%2hhx-%2hhx%2hhx-%2hhx%2hhx%2hhx%2hhx%2hhx%2hhx",
        &uuid.bytes[0], &uuid.bytes[1], &uuid.bytes[2], &uuid.bytes[3],
        &uuid.bytes[4], &uuid.bytes[5],
        &uuid.bytes[6], &uuid.bytes[7],
        &uuid.bytes[8], &uuid.bytes[9],
        &uuid.bytes[10], &uuid.bytes[11], &uuid.bytes[12], &uuid.bytes[13], &uuid.bytes[14], &uuid.bytes[15]);
    return uuid;
}

// UUID 비교
int uuid_equals(uuid_t a, uuid_t b) {
    return memcmp(a.bytes, b.bytes, 16) == 0;
}

// UUID 무효 여부 확인
int uuid_is_nil(uuid_t uuid) {
    for (int i = 0; i < 16; i++) {
        if (uuid.bytes[i] != 0) return 0;
    }
    return 1;
}

// 스레드 안전 UUID 생성
static pthread_mutex_t uuid_mutex = PTHREAD_MUTEX_INITIALIZER;

uuid_t uuid_v4_generate_thread_safe(void) {
    pthread_mutex_lock(&uuid_mutex);
    uuid_t uuid = uuid_v4_generate();
    pthread_mutex_unlock(&uuid_mutex);
    return uuid;
}

