    ->from(query, "users")
    ->where(query, "age", ">", "18")
    ->limit(query, 10);

char *sql = knex_to_sql(select);
// Output: SELECT id, name, email FROM users WHERE age > 18 LIMIT 10

// INSERT
knex_builder_t *insert = knex_insert(query, "users")
    ->values(query, "name", "John")
    ->values(query, "email", "john@example.com");

// UPDATE
